64: void ListenersHandler::writeListenersAsJson(Buffer::Instance& response) {
65:   envoy::admin::v3::Listeners listeners;
66:   for (const auto& listener : server_.listenerManager().listeners()) {
67:     envoy::admin::v3::ListenerStatus& listener_status = *listeners.add_listener_statuses();
68:     listener_status.set_name(listener.get().name());
69:     Network::Utility::addressToProtobufAddress(
70:         *listener.get().listenSocketFactories()[0]->localAddress(),
71:         *listener_status.mutable_local_address());
72:     for (std::vector<Network::ListenSocketFactoryPtr>::size_type i = 1;
73:          i < listener.get().listenSocketFactories().size(); i++) {
74:       auto address = listener_status.add_additional_local_addresses();
75:       Network::Utility::addressToProtobufAddress(
76:           *listener.get().listenSocketFactories()[i]->localAddress(), *address);
77:     }
78:   }
79:   response.add(MessageUtil::getJsonStringFromMessageOrError(listeners, true)); // pretty-print
80: }
81: 
82: void ListenersHandler::writeListenersAsText(Buffer::Instance& response) {
83:   for (const auto& listener : server_.listenerManager().listeners()) {
84:     for (auto& socket_factory : listener.get().listenSocketFactories()) {
85:       response.add(fmt::format("{}::{}\n", listener.get().name(),
86:                                socket_factory->localAddress()->asString()));
87:     }
88:   }
89: }
